const mapStyles = {
  light: [
    {
      elementType: 'geometry',
      stylers: [{ color: '#f5f5f5' }],
    },
    {
      elementType: 'labels.text.fill',
      stylers: [{ color: '#1F2937' }], // Matches index.css text-gray-800
    },
    {
      elementType: 'labels.text.stroke',
      stylers: [{ color: '#ffffff' }, { weight: 0.5 }],
    },
    {
      featureType: 'road',
      elementType: 'geometry',
      stylers: [{ color: '#d1d5db' }], // Matches index.css gray-300
    },
    {
      featureType: 'road',
      elementType: 'labels.text.fill',
      stylers: [{ color: '#4b5563' }], // Matches index.css gray-600
    },
    {
      featureType: 'road.highway',
      elementType: 'geometry',
      stylers: [{ color: '#3B82F6' }], // Matches index.css blue-500
    },
    {
      featureType: 'water',
      elementType: 'geometry',
      stylers: [{ color: '#bfdbfe' }], // Light blue for water
    },
    {
      featureType: 'poi',
      elementType: 'geometry',
      stylers: [{ color: '#e5e7eb' }], // Matches index.css gray-200
    },
    {
      featureType: 'poi',
      elementType: 'labels.text.fill',
      stylers: [{ color: '#6b7280' }], // Matches index.css gray-500
    },
  ],
  dark: [
    {
      elementType: 'geometry',
      stylers: [{ color: '#1F2937' }], // Matches index.css gray-800
    },
    {
      elementType: 'labels.text.fill',
      stylers: [{ color: '#d1d5db' }], // Matches index.css gray-300
    },
    {
      elementType: 'labels.text.stroke',
      stylers: [{ color: '#1f2937' }, { weight: 0.5 }],
    },
    {
      featureType: 'road',
      elementType: 'geometry',
      stylers: [{ color: '#4b5563' }], // Matches index.css gray-600
    },
    {
      featureType: 'road',
      elementType: 'labels.text.fill',
      stylers: [{ color: '#9ca3af' }], // Matches index.css gray-400
    },
    {
      featureType: 'road.highway',
      elementType: 'geometry',
      stylers: [{ color: '#3B82F6' }], // Matches index.css blue-500
    },
    {
      featureType: 'water',
      elementType: 'geometry',
      stylers: [{ color: '#374151' }], // Darker blue-gray
    },
    {
      featureType: 'poi',
      elementType: 'geometry',
      stylers: [{ color: '#374151' }], // Matches index.css gray-700
    },
    {
      featureType: 'poi',
      elementType: 'labels.text.fill',
      stylers: [{ color: '#9ca3af' }], // Matches index.css gray-400
    },
  ],
  highContrast: [
    {
      elementType: 'geometry',
      stylers: [{ color: '#ffffff' }],
    },
    {
      elementType: 'labels.text.fill',
      stylers: [{ color: '#000000' }],
    },
    {
      elementType: 'labels.text.stroke',
      stylers: [{ color: '#ffffff' }, { weight: 1 }],
    },
    {
      featureType: 'road',
      elementType: 'geometry',
      stylers: [{ color: '#000000' }],
    },
    {
      featureType: 'road.highway',
      elementType: 'geometry',
      stylers: [{ color: '#3B82F6' }], // Matches index.css blue-500
    },
    {
      featureType: 'water',
      elementType: 'geometry',
      stylers: [{ color: '#1e40af' }], // Darker blue
    },
    {
      featureType: 'poi',
      elementType: 'geometry',
      stylers: [{ visibility: 'off' }],
    },
  ],
};

export default mapStyles;
